  // ENGINE — identical across all 433-A asset widgets.
  // ============================================================
  var OVR = (typeof window !== 'undefined' && window[CONFIG.configGlobal]) || {};
  var MAX = OVR.max || 10;

  // Shared host-field wrapper selector (the label+input row GHL renders) — used by
