    var t = String(s).trim();
    if (t === '') return null;
    var neg = /^\(.*\)$/.test(t) || /^-/.test(t);  // accounting parens or leading minus = negative
    // strip ONLY currency symbol, thousands separators, surrounding parens/sign/space — never interior junk
