  // ---------- brand color ----------
  function isValidColor(v) { if (!v || typeof v !== 'string') return false; var s = v.trim(); if (!s || s.indexOf('{{') !== -1 || s.indexOf('}}') !== -1) return false; return /^#[0-9a-f]{3,8}$/i.test(s) || /^rgba?\(/i.test(s); }
